function timer_handler(emit)
	emit(make_counter(counter))
	counter = 0
end

function shutdown(emit)
	emit(make_counter(counter))
end

function make_counter(value)
	return metric = {
		name = "event_counter",
		kind = "incremental",
		timestamp = os.date("!*t"),
		counter = {
			value = value
		}
 	}
end
